import os
import tarfile

def backup_directory(directory_name):
    archive_name = directory_name + '.tar.gz'
    with tarfile.open(archive_name, 'w:gz') as tar:
        tar.add(directory_name, arcname=os.path.basename(directory_name))

if __name__ == '__main__':
    directory_name = input('Enter directory name to backup: ')
    backup_directory(directory_name)